var countMajoritySubarrays = function(nums, target) {
    const n = nums.length;
    const pref = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) pref[i + 1] = pref[i] + (nums[i] === target ? 1 : -1);
    let ans = 0;
    for (let j = 0; j <= n; j++) {
        for (let i = 0; i < j; i++) {
            if (pref[i] < pref[j]) ans++;
        }
    }
    return ans;
};
